function solve(s) {
    const segments = [];
    const seen = new Set();
    let start = 0;
    let i = 0;
    const n = s.length;
    while (i < n) {
        const substr = s.substring(start, i + 1);
        if (!seen.has(substr)) {
            segments.push(substr);
            seen.add(substr);
            start = i + 1;
            i = start;
        } else {
            i++;
        }
    }
    return segments;
}
```

